SELECT statement_id, statement, sentiment_score
FROM statements
ORDER BY sentiment_score DESC;

SELECT statement, AVG(confidence_score) AS average_confidence
FROM statements
GROUP BY statement;

SELECT COUNT(statement_id) AS statement_count
FROM statements
WHERE language = 'English' AND region = 'United States';

SELECT statement, date, verdict_name
FROM statements
JOIN verdicts ON statements.verdict_id = verdicts.verdict_id;

SELECT COUNT(statement_id) AS statement_count
FROM statements
WHERE author_id = 123;
